screen_flow_psbtViewBase::~screen_flow_psbtViewBase()
{
    touchgfx::CanvasWidgetRenderer::resetBuffer();
}

void screen_flow_psbtViewBase::setupScreen()
{
    get_cryptogram_thinking_circles.initialize();
    s3_typePassword.initialize();
    close_button.initialize();
}

void screen_flow_psbtViewBase::flexButtonCallbackHandler(const touchgfx::AbstractButtonContainer& src)
{
    if (&src == &btn_verify_transaction_info_1)
    {
        //btnVerifyTransactionPressed
        //When btn_verify_transaction_info_1 clicked call virtual function
        //Call btnVerifyTransactionPressed
        btnVerifyTransactionPressed();
    }
    if (&src == &card_format_error_btn)
    {
        //retryCardFormatErrorPressed
        //When card_format_error_btn clicked call virtual function
        //Call retryCardFormatErrorPressed
        retryCardFormatErrorPressed();
    }
    if (&src == &no_cryptogram_error_btn)
    {
        //retryNoCryptogramErrorPressed
        //When no_cryptogram_error_btn clicked call virtual function
        //Call retryNoCryptogramErrorPressed
        retryNoCryptogramErrorPressed();
    }
    if (&src == &btn_check_receiver)
    {
        //checkReceiverPressed
        //When btn_check_receiver clicked call virtual function
        //Call checkReceiverPressed
        checkReceiverPressed();
    }
    if (&src == &ko_private_password_btn)
    {
        //koPrivatePasswordBtnPressed
        //When ko_private_password_btn clicked call virtual function
        //Call koPrivatePasswordBtnPressed
        koPrivatePasswordBtnPressed();
    }
    if (&src == &btn_sign_psbt)
    {
        //btnSignPsbtPressed
        //When btn_sign_psbt clicked call virtual function
        //Call btnSignPsbtPressed
        btnSignPsbtPressed();
    }
    if (&src == &no_change_address_warning_btn)
    {
        //btnWarningNoChangeAddressPressed
        //When no_change_address_warning_btn clicked call virtual function
        //Call btnWarningNoChangeAddressPressed
        btnWarningNoChangeAddressPressed();
    }
    if (&src == &btn_send_to_app)
    {
        //btnSendToAppPressed
        //When btn_send_to_app clicked call virtual function
        //Call btnSendToAppPressed
        btnSendToAppPressed();
    }
    if (&src == &card_size_error_btn)
    {
        //retryCardSizeErrorPressed
        //When card_size_error_btn clicked call virtual function
        //Call retryCardSizeErrorPressed
        retryCardSizeErrorPressed();
    }
    if (&src == &btn_connect_app_msg)
    {
        //btnConnectAppMsgPressed
        //When btn_connect_app_msg clicked call virtual function
        //Call btnConnectAppMsgPressed
        btnConnectAppMsgPressed();
    }
    if (&src == &btn_success_1)
    {
        //success1Pressed
        //When btn_success_1 clicked call virtual function
        //Call success1Pressed
        success1Pressed();
    }
    if (&src == &btn_success_2)
    {
        //success2Pressed
        //When btn_success_2 clicked call virtual function
        //Call success2Pressed
        success2Pressed();
    }
}

void screen_flow_psbtViewBase::handleTickEvent()
{
    frameCountTickEventInterval++;
    if(frameCountTickEventInterval == TICK_TICKEVENT_INTERVAL)
    {
        //tickEvent
        //When every N tick call virtual function
        //Call tickEventScreen
        tickEventScreen();
        frameCountTickEventInterval = 0;
    }
}
